const fs = require('fs');
const rules = JSON.parse(fs.readFileSync('/data/pravidla.json', 'utf8'));
return rules.map(function(r){ return { json: r }; });

const urlItem = $('Loop pres URL').item.json;
const rules = items.map(function(i){ return i.json; });
return [{ json: Object.assign({}, urlItem, { _rules: rules }) }];

const srcItem = $('Loop pres URL').item.json;
const vzor = (srcItem.url_vzor || '').toLowerCase();
const baseUrl = srcItem.url || '';
const html = String(items[0].json.data || items[0].json.body || '');
var links = [];
var re = /href=["']([^"'#][^"']*)["']/gi;
var match;
while ((match = re.exec(html)) !== null) {
  var href = match[1];
  if (href.startsWith('http')) {
  } else if (href.startsWith('/')) {
    var base = baseUrl.match(/^(https?:\/\/[^\/]+)/);
    href = base ? base[1] + href : href;
  } else { continue; }
  if (vzor && href.toLowerCase().indexOf(vzor) === -1) continue;
  if (links.indexOf(href) === -1) links.push(href);
}
return links.map(function(url) {
  return { json: {
    odkaz_inzeratu: url,
    zdroj_nazev: srcItem.nazev || baseUrl,
    zdroj_url: baseUrl
  }};
});

const loopItem = $('Loop pres inzerat').item.json;
const odkaz = loopItem.odkaz_inzeratu || '';
const zdroj_nazev = loopItem.zdroj_nazev || '';
const zdroj_url = loopItem.zdroj_url || '';
const html = String(items[0].json.data || items[0].json.body || '');
const text = html.replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
  .replace(/\s+/g, ' ').trim();
var nazev = '', m;
m = html.match(/<h1[^>]*>([\s\S]{1,200}?)<\/h1>/i);
if (m) nazev = m[1].replace(/<[^>]+>/g, '').trim();
if (!nazev) { m = html.match(/og:title[^>]*content=["']([^"']+)["']/i); if (m) nazev = m[1].trim(); }
if (!nazev) { m = html.match(/<title[^>]*>([^<]+)<\/title>/i); if (m) nazev = m[1].replace(/[|\-\u2013].*/,'').trim(); }
var firma = '';
m = html.match(/hiringOrganization[\s\S]{0,300}?"name":\s*"([^"]{1,100})"/i);
if (m) firma = m[1];
if (!firma) { m = html.match(/og:site_name[^>]*content=["']([^"']+)["']/i); if (m) firma = m[1].trim(); }
var lokalita = '';
m = html.match(/addressLocality["':\s]+([^\s"'}{,]{2,50})/i);
if (m) lokalita = m[1].trim();
return [{ json: {
  nazev_pozice: nazev.substring(0, 150),
  firma: firma.substring(0, 100),
  lokalita: lokalita.substring(0, 100),
  popis: text.substring(0, 3000),
  odkaz_inzeratu: odkaz,
  zdroj_nazev: zdroj_nazev,
  zdroj_url: zdroj_url
}}];

const j = items[0].json;
const allRules = $('Spoj pravidla s URL').item.json._rules || [];
const haystack = (j.nazev_pozice + ' ' + j.firma + ' ' + j.lokalita + ' ' + j.popis).toLowerCase();
var skore = 0, matched = [];
allRules.forEach(function(r) {
  if (haystack.indexOf((r.pravidlo||'').toLowerCase()) !== -1) {
    skore += (r.vaha || 0);
    matched.push(r.pravidlo + '(' + (r.vaha > 0 ? '+' : '') + r.vaha + ')');
  }
});
skore = Math.max(1, Math.min(10, skore));
return [{ json: Object.assign({}, j, { prescoring: skore, prescoring_match: matched.join(', ') }) }];

const fs = require('fs');
const j = $('Pre-scoring').item.json;
const soubor = '/data/vysledky.json';
var vysledky = [];
try { vysledky = JSON.parse(fs.readFileSync(soubor, 'utf8')); } catch(e) {}
// Dedup podle odkazu
const odkaz = j.odkaz_inzeratu || '';
const existuje = vysledky.some(function(v){ return v.odkaz === odkaz; });
if (existuje) {
  return [{ json: { preskoceno: true, odkaz: odkaz } }];
}
// Pridej novy zaznam
const zaznam = {
  datum: new Date().toISOString().slice(0,19).replace('T',' '),
  zdroj_nazev: j.zdroj_nazev || '',
  zdroj_url: j.zdroj_url || '',
  nazev_pozice: j.nazev_pozice || '',
  firma: j.firma || '',
  lokalita: j.lokalita || '',
  odkaz: odkaz,
  prescoring: j.prescoring || 1,
  match_pravidla: j.prescoring_match || '',
  popis: j.popis || '',
};
vysledky.push(zaznam);
vysledky.sort(function(a,b){ return b.prescoring - a.prescoring; });
fs.writeFileSync(soubor, JSON.stringify(vysledky, null, 2), 'utf8');
return [{ json: Object.assign({}, zaznam, { ulozeno: true }) }];
